/**
 * @fileoverview Breadcrumb component — modular entry point.
 * @module module/Breadcrumb
 */

import { default as razyui } from '../../index.js';
import { BreadcrumbDef as DEF } from '../Breadcrumb.def.js';
import { DEFAULTS } from './constants.js';
import { renderDOM, cleanupDOM } from './view.js';

const Breadcrumb = class {
    #root     = null;
    #destroyed = false;
    #config   = {};

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Breadcrumb: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };

        renderDOM(root, this.#config.items, this.#config.separator);
    }

    setItems(items) {
        this.#config.items = items;
        renderDOM(this.#root, items, this.#config.separator);
    }

    setSeparator(sep) {
        this.#config.separator = sep;
        renderDOM(this.#root, this.#config.items, sep);
    }

    getControl() {
        const self = this;
        return {
            get separator() { return self.#config.separator; },
            set separator(v){ self.setSeparator(v); },
            setItems:     (items) => self.setItems(items),
            setSeparator: (sep)   => self.setSeparator(sep),
            destroy:      ()      => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        cleanupDOM(this.#root);
    }
};

export default Breadcrumb;
